SELECT student_id, first_name, last_name, email, phone, address, date_of_birth, nationality, gender, emergency_contact
FROM students
WHERE student_id IN (SELECT student_id FROM payments);

SELECT category_name
FROM course_categories
WHERE category_id NOT IN (SELECT category_id FROM course_category_mapping);

SELECT c.course_name, c.course_code, cm.campus_name
FROM courses c
INNER JOIN campuses cm ON c.campus_id = cm.campus_id;
